/* meilleurs buteurs d'une équipe dans cette CdM (openfootball ; passeurs non fournis par la source) */
function topScorers(team){
  const c={};
  for(const id in LIVE.matches){const x=LIVE.matches[id];
    let list=null; if(x.a===team)list=x.g1; else if(x.b===team)list=x.g2;
    (list||[]).forEach(g=>{ if(g.og)return; const k=g.n; (c[k]=c[k]||{n:k,buts:0,pen:0}); c[k].buts++; if(g.pen)c[k].pen++; });
  }
  return Object.values(c).sort((a,b)=>b.buts-a.buts||a.n.localeCompare(b.n));
}
/* forme + buts pour/contre (matchs joués) */
function teamForm(team){
  const ms=teamPathMatches(team).filter(m=>played(m));
  let bp=0,bc=0,res=[];
  ms.forEach(m=>{const d=dispTeams(m);const home=d.a===team;const sf=home?d.sa:d.sb, sa=home?d.sb:d.sa;
    bp+=sf;bc+=sa; res.push(sf>sa?'V':(sf<sa?'D':'N'));});
  return {bp,bc,res,played:ms.length};
}
/* confrontations entre deux équipes DANS cette CdM */
function h2hWC(t1,t2){
  return matches.filter(m=>{const d=dispTeams(m);return (d.a===t1&&d.b===t2)||(d.a===t2&&d.b===t1);}).sort(byDate);
}

/* ===== Soulier d'or : buteurs de tout le tournoi ===== */
function tournamentScorers(){
  const c={};
  for(const id in LIVE.matches){const x=LIVE.matches[id];
    const add=(list,team)=>{(list||[]).forEach(g=>{ if(g.og)return; const key=g.n+'|'+team;
      (c[key]=c[key]||{n:g.n,team,buts:0,pen:0}); c[key].buts++; if(g.pen)c[key].pen++; });};
    if(x.a)add(x.g1,x.a); if(x.b)add(x.g2,x.b);
  }
  return Object.values(c).sort((a,b)=>b.buts-a.buts || a.pen-b.pen || a.n.localeCompare(b.n));
}
/* ===== Passeurs décisifs (affichés si la source les fournit : champs as1/as2) ===== */
function hasAssists(){ for(const id in LIVE.matches){const x=LIVE.matches[id]; if((x.as1&&x.as1.length)||(x.as2&&x.as2.length))return true;} return false; }
function topAssisters(team){
  const c={};
  for(const id in LIVE.matches){const x=LIVE.matches[id];
    let list=null; if(x.a===team)list=x.as1; else if(x.b===team)list=x.as2;
    (list||[]).forEach(a=>{const k=a.n;(c[k]=c[k]||{n:k,pd:0});c[k].pd++;});
  }
  return Object.values(c).sort((a,b)=>b.pd-a.pd||a.n.localeCompare(b.n));
}
function tournamentAssisters(){
  const c={};
  for(const id in LIVE.matches){const x=LIVE.matches[id];
    const add=(list,team)=>{(list||[]).forEach(a=>{const key=a.n+'|'+team;(c[key]=c[key]||{n:a.n,team,pd:0});c[key].pd++;});};
    if(x.a)add(x.as1,x.a); if(x.b)add(x.as2,x.b);
  }
  return Object.values(c).sort((a,b)=>b.pd-a.pd||a.n.localeCompare(b.n));
}

/* ===== Chemin vers la finale : parcours projeté d'une équipe ===== */
function pathToFinal(team){
  const r32=r32MatchOf(team); if(r32==null)return null;
  const chain=chainUp(r32); // [r32, r16, qf, sf, final]
  const out=[]; let aliveTeam=team, eliminated=false;
  for(const mid of chain){
    const m=matchById(mid); const a=resolveTeam(mid,'a'), b=resolveTeam(mid,'b');
    const meHere = (a===aliveTeam||b===aliveTeam);
    const opp = a===aliveTeam ? b : (b===aliveTeam ? a : null);
    let state='avenir', score=null;
    if(played(m)){ const d=dispTeams(m); const w=winnerOf(mid); const myside=a===aliveTeam?'a':'b';
      score=`${d.sa}–${d.sb}${d.status==='PEN'?` (${d.pa}–${d.pb} tab)`:''}`;
      if(meHere){ state = (w===myside)?'gagne':'perdu'; if(w!==myside) eliminated=true; }
    } else if(eliminated){ state='out'; }
    out.push({mid, round:PHASE_LABEL[m.phase]||m.phase, opp, oppKnown:!!opp, state, score, city:m.city,
              kickoffUTC:m.kickoffUTC});
    if(eliminated) break;
  }
  return {chain:out, eliminated, team};
}

/* ============ BUTEURS — Soulier d'or ============ */
let butFilter='Toutes';
let butMode='buts';
function renderButeurs(){
  const scorers=tournamentScorers(), assists=tournamentAssisters(), assistsOK=hasAssists();
  if(!assistsOK) butMode='buts';                       // passeurs masqués tant que la source ne les fournit pas
  const base=butMode==='passes'?assists:scorers;
  const teams=[...new Set(base.map(p=>p.team))].sort((a,b)=>a.localeCompare(b));
  if(butFilter!=='Toutes' && !teams.includes(butFilter)) butFilter='Toutes';
  const val=p=>butMode==='passes'?p.pd:p.buts;
  const unit=butMode==='passes'?'passe':'but';
  const list=(butFilter==='Toutes'?base:base.filter(p=>p.team===butFilter));

  let h=`<p class="lead">${butMode==='passes'
    ?'Meilleurs <b>passeurs</b> 🅰️ de la Coupe du monde.'
    :"Course au <b>Soulier d'or</b> 🥇 — buteurs (csc exclus, pénos comptés ; égalité au moins de penalties)."}</p>`;
  // bascule Buteurs / Passeurs — uniquement si les passes sont disponibles
  if(assistsOK){
    h+=`<div class="chips" style="margin-bottom:10px">
      <button class="chip ${butMode==='buts'?'on':''}" onclick="butMode='buts';renderButeurs()">🥇 Buteurs</button>
      <button class="chip ${butMode==='passes'?'on':''}" onclick="butMode='passes';renderButeurs()">🅰️ Passeurs</button>
    </div>`;
  }
  h+=`<div class="butfilter"><label>Équipe :</label>
    <select onchange="butFilter=this.value;renderButeurs()">
      <option value="Toutes"${butFilter==='Toutes'?' selected':''}>Toutes les équipes</option>
      ${teams.map(t=>`<option value="${jesc(t)}"${butFilter===t?' selected':''}>${esc(t)}</option>`).join('')}
    </select></div>`;
  if(!list.length){ document.getElementById('tab-buteurs').innerHTML=h+'<p class="empty">Aucune donnée pour ce filtre.</p>'; return; }
  if(butFilter==='Toutes'){
    const L=list[0];
    h+=`<div class="gblead"><div class="gbmed">${butMode==='passes'?'🅰️':'🥇'}</div>${flag(L.team,40)}
        <div class="gbinfo"><div class="gbn">${esc(L.n)}</div><div class="gbt">${esc(L.team)}</div></div>
        <div class="gbb"><b class="num">${val(L)}</b><span>${unit}${val(L)>1?'s':''}</span></div></div>`;
  } else {
    const tot=list.reduce((s,p)=>s+val(p),0);
    h+=`<div class="butsum">${flag(butFilter,28)} <b>${esc(butFilter)}</b> — ${tot} ${unit}${tot>1?'s':''} par ${list.length} joueur${list.length>1?'s':''}</div>`;
  }
  h+=`<div class="scorelist">`;
  const medal=i=>['🥇','🥈','🥉'][i]||(i+1);
  list.slice(0,60).forEach((p,i)=>{
    h+=`<div class="scorerow ${i===0&&butFilter==='Toutes'?'lead':''}"><span class="rankn ${i<3&&butFilter==='Toutes'?'top':''} num">${butFilter==='Toutes'?medal(i):(i+1)}</span>
      ${flag(p.team,18)}<div class="srn"><span class="srnm">${esc(p.n)}</span><small>${esc(p.team)}</small></div>
      ${(butMode==='buts'&&p.pen)?`<span class="srp">${p.pen} pén.</span>`:''}<b class="srb num">${val(p)}</b></div>`;
  });
  document.getElementById('tab-buteurs').innerHTML=h+'</div>';
}
function statsHtml(){
  const s=tournamentStats();
  if(!s.played) return '';
  const big=s.biggest?`${esc(s.biggest.a)} ${s.biggest.sa}–${s.biggest.sb} ${esc(s.biggest.b)}`:'—';
  return `<div class="secthead2">📊 Le tournoi en chiffres</div>
    <div class="statstrip">
      <div class="ststat"><b class="num">${s.goals}</b><span>buts</span></div>
      <div class="ststat"><b class="num">${s.avg.toFixed(1)}</b><span>buts / match</span></div>
      <div class="ststat"><b class="num">${s.played}</b><span>matchs joués</span></div>
      <div class="ststat"><b class="num">${s.pens}</b><span>séances t.a.b.</span></div>
    </div>
    <div class="statfacts">
      ${s.topAtt?`<div class="stfact">⚽ Meilleure attaque : ${flag(s.topAtt.team,16)} <b>${esc(s.topAtt.team)}</b> (${s.topAtt.buts} buts)</div>`:''}
      <div class="stfact">💥 Plus large écart : <b>${big}</b></div>
    </div>`;
}
function gbCompact(){
  const list=tournamentScorers(); if(!list.length)return '';
  const top=list.slice(0,3);
  return `<div class="secthead2">🥇 Course au Soulier d'or</div>
    <div class="gbcard">
      ${top.map((p,i)=>`<button class="gbmini" onclick="butFilter='Toutes';showTab('buteurs')">
        <span class="gbmed2">${['🥇','🥈','🥉'][i]}</span>
        ${flag(p.team,22)}
        <div class="gbm-i"><span class="gbm-n">${esc(p.n)}</span><span class="gbm-t">${esc(p.team)}</span></div>
        <span class="gbm-g"><b class="num">${p.buts}</b><small>buts</small></span>
      </button>`).join('')}
      <button class="gbmore" onclick="butFilter='Toutes';showTab('buteurs')">Voir le classement complet ›</button>
    </div>`;
}

